"""
MKT Christ — Mark chapters 7–8
Output: data/commentary/mkt-christ/mark.json
Run: python3 scripts/zc-christ-mark-7-8.py

Key Christological nodes: Christ as fulfillment of Isaiah's purity vision (7:6),
the one who declares all foods clean and opens the covenant to Gentiles (7:19,
7:27–29), the fulfiller of Isa 35:5–6 (7:37), the Lord of both Jewish and Gentile
crowds (8:1–9), and the Son of Man who must suffer (8:31). 8:29 and 8:34 already
present — merge_comm skips them.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys.
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

MARK_CH7_8 = {
  "7": {
    "1": '<p>A theme of Christological conflict: the Pharisees and scribes who have come from Jerusalem gather around Jesus — the religious authorities of the capital now enter the Galilean ministry to interrogate. The gathering of Jerusalem officials at this point signals that the conflict has escalated beyond local disputes; the confrontation that will end at the cross has its theological roots in these controversies over authority, Torah interpretation, and purity.</p>',
    "2": '<p>A theme of ritual purity and the new covenant: the disciples eat with &ldquo;common&rdquo; (koinais — ritually unwashed) hands. The purity system Jesus is about to reinterpret was not peripheral to Jewish identity — it marked the boundary between Israel and the nations. Christ\'s response will redefine that boundary from external ritual to internal character, opening the covenant community to all who have clean hearts rather than clean hands.</p>',
    "3": '<p>A revelation of God\'s purpose through Christ: the parenthetical explanation of Jewish hand-washing customs shows Mark writing for a Gentile audience unfamiliar with these practices. Mark\'s explanatory aside signals that the teaching Jesus is about to give (vv.14–23) is meant precisely for Gentile readers — the declaration that all foods are clean is already addressed to the church that will include them.</p>',
    "4": '<p>A theme of tradition confronting Christ: the Pharisees observe many additional purification requirements for markets, cups, pots, and bronze vessels. These accretions to the written Torah represent the &ldquo;tradition of the elders&rdquo; (v.3) — the oral law that the Pharisees treated as binding. Christ will distinguish between the commandment of God and the tradition of men (v.8), and the distinction will redefine the entire purity framework.</p>',
    "5": '<p>A theme of Christological challenge: the Pharisees and scribes ask why the disciples do not walk according to the tradition of the elders. The question is really about authority — whose interpretation of Torah governs? Christ\'s answer claims an authority over Torah interpretation that transcends the scribal tradition, positioning himself as the one who speaks God\'s commandment rather than expounding it.</p>',
    "6": '<p>A direct citation fulfilled: &ldquo;Isaiah was right when he prophesied about you hypocrites: this people honors me with their lips but their heart is far from me.&rdquo; The citation is Isa 29:13, which Isaiah applied to a form of religion that had substituted human performance for genuine covenant loyalty. Christ applies it to the Pharisees, positioning himself as the one in whose ministry the prophetic critique finds its final referent — and who will inaugurate the new covenant written on hearts (Jer 31:33), not performed with hands.</p>',
    "7": '<p>A direct citation: &ldquo;in vain do they worship me, teaching as doctrines the commandments of men.&rdquo; The second half of the Isaiah citation identifies the specific failure: human traditions elevated to divine status. Christ as the Word of God (John 1:1) is the authoritative divine commandment — his teaching does not supplement the tradition of the elders but supersedes it as the genuine voice of God that the tradition claimed to preserve.</p>',
    "8": '<p>A revelation of Christ\'s authority over Torah: &ldquo;You leave the commandment of God and hold to the tradition of men.&rdquo; Christ distinguishes the commandment of God (which he upholds and fulfills) from the tradition of men (which he sets aside). This distinction is foundational to his teaching ministry — he does not abolish the Torah but fulfills it (Matt 5:17), cutting through the interpretive overlay to reveal the original divine intent that the oral tradition had obscured.</p>',
    "9": '<p>A revelation of Christological authority: Jesus says &ldquo;You have a fine way of rejecting the commandment of God in order to establish your tradition.&rdquo; The irony is sharp — the keepers of Torah have inverted its priorities. Christ speaks as the one who knows the commandment\'s original intent because he is the Word through whom it was given. His interpretive authority is not a teacher\'s superior scholarship but the Author\'s knowledge of his own text.</p>',
    "10": '<p>A direct citation: &ldquo;Moses said, Honor your father and your mother, and Whoever reviles father or mother must surely die.&rdquo; Christ cites the fifth commandment (Exod 20:12; Deut 5:16) and its capital sanction (Exod 21:17; Lev 20:9) as the standard being violated by the corban practice. His appeal to Moses\' commandment against the oral law\'s corban extension shows him as the champion of Torah\'s original intent against its corruption — a role he fulfills definitively at the cross where he honors the Father perfectly.</p>',
    "11": '<p>A revelation of Christ exposing religious exploitation: the corban (qorban) formula allowed a person to declare property dedicated to God, thereby exempting it from parental support while retaining personal use. Christ identifies this as a mechanism that uses the language of devotion to God to avoid the commandment of God. The same critique applies wherever religious performance is used as cover for disobeying God\'s moral demands — a pattern Christ addresses throughout his ministry.</p>',
    "12": '<p>A theme of Christ and Torah\'s priority: &ldquo;you no longer permit him to do anything for his father or mother.&rdquo; The oral tradition\'s corban ruling created a binding legal outcome that contradicted the written Torah. Christ\'s correction restores the commandment\'s priority — and the principle he establishes (God\'s written commandment over human interpretive tradition) is the hermeneutic that governs his own interpretive method throughout Mark.</p>',
    "13": '<p>A revelation of Christ\'s understanding of tradition\'s corruption: &ldquo;making void the word of God by your tradition that you have handed on. And many such things you do.&rdquo; The word of God (logos tou theou) that human tradition nullifies is the commandment Christ upholds. The contrast between the word of God and human tradition is the contrast between Christ\'s teaching and the scribal method — he speaks what God originally said; they speak what men have added to it.</p>',
    "14": '<p>A revelation of Christ calling all to hear: Jesus calls the crowd to him and says, &ldquo;Hear me, all of you, and understand.&rdquo; The summons to universal hearing (pantas — everyone) before the clean/unclean declaration is Christological: he is about to speak a principle that will open the covenant to all peoples. The call to &ldquo;hear and understand&rdquo; echoes the Shema structure — the hearing that Israel was commanded to do is now directed toward Christ\'s word.</p>',
    "15": '<p>A direct revelation: &ldquo;Nothing outside a person can defile them by going in; rather, it is what comes out that defiles.&rdquo; This is the central Christological principle of the purity controversy and one of Jesus\'s most radical teachings. The entire Levitical food-law system was predicated on external contact producing impurity; Christ locates defilement in the moral life of the heart. The new covenant promise of a clean heart (Ezek 36:26) is being enacted: Christ speaks the principle that the Spirit will fulfill in his people.</p>',
    "16": '<p>A revelation of Christ\'s call to spiritual hearing: &ldquo;If anyone has ears to hear, let him hear.&rdquo; The formula is used at moments of special revelation — it marks what has just been said as a teaching that requires spiritual perception, not merely intellectual processing. The inability of the disciples to understand it (v.18) shows that the new-covenant ear — the circumcised heart — is not yet universally present. That transformation will come through Christ\'s Spirit after Pentecost.</p>',
    "17": '<p>A theme of progressive revelation: in the house, away from the crowd, the disciples ask Jesus about the parable. The pattern of public teaching followed by private explanation to the inner circle runs throughout Mark (4:10–20, 9:28, 10:10) — the house is the space where deeper disclosure happens. The disciples\' need for private explanation reflects their incomplete understanding, which Mark presents as the normal pre-resurrection condition that the Spirit will rectify.</p>',
    "18": '<p>A revelation of Christ\'s patience with slow understanding: &ldquo;Are you also without understanding?&rdquo; The disciples\' inability to grasp the clean/unclean principle — even after private explanation — is the kind of dullness Mark documents throughout the pre-resurrection narrative. Christ is patient with incomplete perception while consistently pressing toward full understanding. The disciples who fail to understand now will be the ones who preach the Gentile mission later, once the Spirit has opened their ears.</p>',
    "19": '<p>A direct revelation: the parenthetical &ldquo;In saying this, he declared all foods clean&rdquo; is Mark\'s interpretive comment on the Christological implications of 7:15. The declaration that defiling comes from within, not without, has as its direct corollary the abolition of the Levitical food distinctions. This is a new-covenant act: Christ as the divine Lawgiver declares the purity code fulfilled in himself and no longer binding. Acts 10:15 (&ldquo;What God has made clean, do not call common&rdquo;) is the Spirit confirming what Christ declared here.</p>',
    "20": '<p>A theme of the heart\'s corruption addressed by Christ: &ldquo;What comes out of a person is what defiles him.&rdquo; The teaching locates the locus of corruption in the human heart — the same diagnosis given in Gen 6:5 (&ldquo;every intention of the heart was only evil&rdquo;) and Jer 17:9 (&ldquo;the heart is deceitful&rdquo;). Christ comes to address that root, not merely manage its symptoms. The new covenant promise (Jer 31:31–34; Ezek 36:26) is the divine response to this diagnosis, and Christ is its mediator.</p>',
    "21": '<p>A revelation of Christ diagnosing the human condition: the catalog of evils that proceed from the heart — evil thoughts, sexual immorality, theft, murder, adultery — is a Christological statement about why the incarnation was necessary. These are not peripheral failures requiring correction but symptoms of a fundamental disorder of the will that only the one who can give a new heart (Ezek 36:26) can remedy. Christ names what he has come to heal.</p>',
    "22": '<p>A theme of the inner corruption Christ overcomes: coveting, wickedness, deceit, sensuality, envy, slander, pride, foolishness — the second half of the catalog. These are the works of the flesh (Gal 5:19–21) that Christ\'s atonement addresses at the root. The purpose of naming them is not condemnation but diagnosis — Christ is the physician (2:17) who knows the disease perfectly because he has come to bear it and cure it.</p>',
    "23": '<p>A direct revelation: &ldquo;All these evil things come from within and defile a person.&rdquo; The conclusion of the purity discourse reframes the entire Levitical cleansing system: the defilement it was pointing at is moral and spiritual, not ceremonial. The law\'s external cleanness provisions were pedagogical — they taught the concept of holiness and the necessity of God\'s cleansing. Christ fulfills that pedagogy and delivers the reality: the Spirit-wrought inner cleanness (Titus 3:5) that the washings symbolized.</p>',
    "24": '<p>A revelation of Christ breaking geographic barriers: Jesus departs to the region of Tyre and Sidon — Gentile territory, outside the covenant land. The movement is deliberate and anticipates the Gentile mission: the one who declared all foods clean now crosses the boundary into Gentile space. His attempted privacy (he did not want anyone to know) is overcome by the need of a Gentile woman — as the privacy of his early Galilean ministry was repeatedly overcome by need.</p>',
    "25": '<p>A revelation of Christ\'s reputation crossing ethnic lines: a Syrophoenician woman hears of him and comes to fall at his feet. The woman is Greek (Hellēnis) and Syrophoenician by birth — a double Gentile identity. The posture of falling at his feet is the posture of worship and supplication that only the truly great can evoke. Christ is being approached with the kind of desperate faith that Mark has already shown produces miracles — the faith of the four men (2:4), the woman with bleeding (5:27), Jairus (5:22).</p>',
    "26": '<p>A theme of persistent faith: the woman begs Jesus to cast the demon out of her daughter. The request is simple and urgent — no theological sophistication, no membership in Israel, no legal claim on the covenant. She comes with need and faith alone. The response Jesus gives (v.27) tests that faith rather than immediately granting it — and she passes the test, demonstrating the quality of faith that receives from Christ regardless of ethnic status.</p>',
    "27": '<p>A direct revelation of covenant priority and expansion: &ldquo;Let the children be fed first, for it is not right to take the children\'s bread and throw it to the dogs.&rdquo; The &ldquo;first&rdquo; (prōton) is the key word — Paul will use it in Romans 1:16 (&ldquo;to the Jew first and also to the Greek&rdquo;). Jesus is not denying Gentile access but stating the covenantal sequence: Israel is the vessel of the promise, the one through whom the Messiah comes, and through whom blessing flows to the nations (Gen 12:3). The children eat first; the others then eat.</p>',
    "28": '<p>A direct revelation through the woman\'s response: &ldquo;Lord, even the dogs under the table eat the children\'s crumbs.&rdquo; The woman accepts the covenantal priority but claims the overflow — the Gentile\'s portion is not the primary inheritance but the abundance that spills from it. Jesus grants the request immediately: her answer is the answer of faith that grasps how the covenant works. The crumbs from the children\'s table are sufficient for her daughter\'s healing — a prefiguration of Gentile salvation through Israel\'s Messiah.</p>',
    "29": '<p>A direct revelation: &ldquo;For this statement you may go your way; the demon has left your daughter.&rdquo; The healing word is spoken at a distance — Christ does not go to the girl, does not touch her, does not require her presence. The word alone is sufficient across Gentile geographic space. This is the only Markan healing granted on the basis of the petitioner\'s argument rather than physical contact or presence — a Christological statement that his authority is not spatially limited by the covenant boundaries.</p>',
    "30": '<p>A theme of Christ\'s authority over the demonic in Gentile space: the woman goes home and finds the child lying on the bed with the demon gone. The result is the same as every exorcism in Jewish territory — complete, immediate, confirmed. Christ\'s authority over demonic powers is universal, not ethnically bounded. The Gentile child receives the same liberation as those in Capernaum. The mission that will be commanded after the resurrection (16:15) is already being enacted in miniature.</p>',
    "31": '<p>A theme of Christ\'s movement through Gentile regions: Jesus returns from Tyre through Sidon to the Sea of Galilee via the Decapolis — a route through largely Gentile territory. The geographic circuit is significant: the declaration that all foods are clean (7:19) is followed by extended presence in Gentile lands. The theological shift produces the geographic shift; the one who has opened the covenant boundary moves through the space beyond it.</p>',
    "32": '<p>A revelation of Christ as healer: people bring a deaf-mute man and beg Jesus to lay his hand on him. The deaf and mute condition is both physical and symbolic — the inability to hear and speak is the condition of the spiritually deaf and mute whom Christ\'s kingdom comes to restore (Isa 35:5–6). The begging community intercedes for one who cannot speak for himself; the healing Christ is approached through others\' faith on behalf of the one in need.</p>',
    "33": '<p>A revelation of Christ\'s compassion in method: Jesus takes the man aside privately, puts his fingers in his ears, spits, and touches his tongue. The unusual physical gestures (unique in the Gospels to this healing and the two-stage blind man healing in 8:22–26) communicate the healing intention through action to one who cannot hear the word. Christ accommodates himself to the man\'s condition — he meets the deaf man in the language of touch and gesture, not speech.</p>',
    "34": '<p>A direct revelation: looking up to heaven, Jesus sighs and says &ldquo;Ephphatha&rdquo; — &ldquo;Be opened.&rdquo; The upward look signals the filial relationship (the Son acting in dependence on the Father); the sigh (stenazō) signals genuine compassionate engagement with human brokenness. &ldquo;Be opened&rdquo; is the language of creation (God who opens the ears of the deaf in Isa 35:5) spoken by the Son in his own name. The Aramaic is preserved — one of Mark\'s instances of the original healing word retained as a mark of authentic testimony.</p>',
    "35": '<p>A direct fulfillment of Isaiah: immediately his ears were opened and his tongue was released and he spoke plainly. Isaiah 35:5–6 prophesied that when God returned to save his people, the deaf would hear and the mute would sing. The deaf-mute restored to full hearing and speech is the fulfillment of that prophecy — the messianic age has arrived in Jesus\'s person and ministry. The word &ldquo;plainly&rdquo; (orthos) suggests not just speech but correct, clear speech — the full restoration of the communication faculty.</p>',
    "36": '<p>A theme of the Messianic Secret: Jesus commands them to tell no one, but the more he charges them, the more zealously they proclaim it. The irony structures the Markan secrecy motif: the identity that cannot be contained cannot be silenced. The one who commands silence produces proclamation. After the resurrection, what was commanded in silence will be commanded in proclamation (16:15); the secret of the cross becomes the gospel of the resurrection.</p>',
    "37": '<p>A direct revelation through acclamation: &ldquo;He has done all things well; he even makes the deaf hear and the mute speak.&rdquo; The echo of Gen 1:31 (&ldquo;God saw all that he had made, and it was very good&rdquo;) is deliberate — the crowd uses the Creator\'s language of assessment for what Jesus has done. The new creation has begun: the one whose word was &ldquo;good&rdquo; at the first creation speaks the word that restores broken creation to its original goodness. This is the healing that only God can perform (Ps 94:9).</p>'
  },
  "8": {
    "1": '<p>A revelation of Christ\'s compassion for all: in those days a large crowd gathers again — &ldquo;again&rdquo; links this to the feeding of the five thousand (6:34–44), but the setting is the Decapolis (Gentile territory). The second feeding is for a largely Gentile crowd; the Lord who fed Israel in the wilderness now feeds the nations. The two feedings bracket the purity controversy and the Syrophoenician healing, forming a structural argument: Christ feeds all who come to him.</p>',
    "2": '<p>A direct revelation of Christ\'s compassion: &ldquo;I have compassion on the crowd, because they have been with me now three days and have nothing to eat.&rdquo; The three days with Jesus in the wilderness anticipates the three days in the tomb — the community that follows Christ through the wilderness of suffering will be fed on the other side. The compassion (splanchnizomai — the same word as 6:34) is the divine gut-level empathy that moved Christ to feed, heal, and ultimately die for those he loves.</p>',
    "3": '<p>A revelation of Christ\'s knowledge of human frailty: &ldquo;if I send them away hungry to their homes, they will faint on the way. And some of them have come from far away.&rdquo; The &ldquo;far away&rdquo; (makrothen) echoes Gentile inclusion in Israel\'s worship (Isa 60:4; Acts 2:39 — &ldquo;all who are far off&rdquo;). Christ sees the Gentile crowd\'s need and refuses to send them away unsatisfied, anticipating the gospel\'s logic: all who come from far away to Christ will be fed, not turned away.</p>',
    "4": '<p>A theme of the disciples\' limited understanding: the disciples ask, &ldquo;How can one feed these people with bread here in this desolate place?&rdquo; They have witnessed the feeding of the five thousand and still ask this question — the same bread, the same wilderness, the same Teacher. Their incomprehension is not stupidity but the pre-resurrection blindness that Mark documents throughout; the opened eyes of faith (8:22–26 as a type) have not yet arrived. Their question becomes the occasion for the demonstration.</p>',
    "5": '<p>A revelation of Christ\'s sufficiency: Jesus asks, &ldquo;How many loaves do you have?&rdquo; The answer is seven. As in the first feeding, the provision begins from what is already in hand — Christ multiplies the inadequate into the abundant. The number seven is the number of completion and covenant (Gen 2:2; Exod 20:8; Deut 16:9); the seven loaves for the Gentile crowd suggest that the covenant abundance that was Israel\'s is being extended to its full number.</p>',
    "6": '<p>A revelation of Christ\'s eucharistic pattern: he directs the crowd to recline on the ground, takes the seven loaves, gives thanks, breaks them, and gives them to the disciples to set before the people. The fourfold action — take, bless, break, give — is the same pattern as 6:41, 14:22, and the post-resurrection meal in Luke 24:30. Christ is establishing the pattern that the Last Supper will make explicit: all feeding from him has the character of gift, thanksgiving, and broken bread. The Lord\'s Supper is the permanent form of what the feeding miracles enacted.</p>',
    "7": '<p>A theme of abundance: they also had a few small fish, and he blessed and said to serve these also. Even the supplementary provision (the fish, as at the first feeding) is handled with the same blessing and thanksgiving. Christ does not compartmentalize the sacred and secular — the fish that feeds the body receives the same blessing as the bread. Everything provided through his hands is grace.</p>',
    "8": '<p>A direct revelation of messianic superabundance: they ate and were satisfied, and the disciples took up seven baskets of broken pieces left over. The seven baskets (spyris — the larger Gentile basket, as opposed to the kophinos of 6:43) suggest the nations\' share of the abundance. The leftover excess is greater than the need — the messianic feast always overflows. Christ provides not merely enough but abundance, fulfilling the eschatological promise of Isa 25:6 (&ldquo;a feast of rich food for all peoples&rdquo;).</p>',
    "9": '<p>A revelation of Christ\'s inclusive provision: about four thousand were fed, and he sent them away. The round number four thousand (compared with five thousand for the Jewish feeding) is not an exact census but the scale of the provision. The sending away (apolysas) is the same word used for dismissing the five thousand crowd (6:45) — the Lord has fed and released both communities from his presence, both on the same pattern of compassionate provision, broken bread, and satisfaction.</p>',
    "10": '<p>A theme of Christ\'s movement: he immediately got into the boat with his disciples and went to the district of Dalmanutha. The return to Jewish territory (Dalmanutha is near Magdala on the western shore) sets up the Pharisees\' confrontation (vv.11–13). The movement from Gentile feeding to Jewish challenge frames the contrast: the Gentiles received what was given without demanding a sign; the Pharisees demand a sign after Jesus has fed thousands and healed dozens.</p>',
    "11": '<p>A revelation of Christ\'s refusal to perform on demand: the Pharisees came and began to argue with him, seeking from him a sign from heaven to test him. The sign-demand is a theological test — they are not open to persuasion but seeking to trap. The &ldquo;sign from heaven&rdquo; they request would be a celestial portent that compels belief without faith. Christ refuses because compelled belief is not the covenant relationship he is establishing; he has already given every sign a willing heart needs.</p>',
    "12": '<p>A direct revelation: sighing deeply in his spirit, Jesus says &ldquo;Why does this generation seek a sign? Truly, no sign will be given to this generation.&rdquo; The deep sigh (anastenazō — a more intense form of the sigh in 7:34) is Christ\'s grief at the hardness of heart that demands proof beyond the evidence already given. The generation that has witnessed the feedings, healings, and exorcisms and still demands a sign is the generation whose heart is far from God (7:6). No additional external evidence will produce the faith they lack.</p>',
    "13": '<p>A theme of departure and judgment: leaving them, he got into the boat again and crossed to the other side. The departure after the sign-demand is a form of judgment — the same movement away that the Mishnah associates with the Shekinah withdrawing from an unworthy generation. Christ does not linger where the request is for proof rather than relationship. The departure prefigures the more decisive departure at the cross, when the generation that rejected him is left to face the consequences.</p>',
    "14": '<p>A theme of the disciples\' spiritual dullness: they forgot to bring bread and had only one loaf in the boat. The one loaf in the boat with Jesus — the one who has just fed four thousand — is the ironic frame for the warning that follows. The disciples\' anxiety about physical bread immediately after two miraculous feedings is Mark\'s documentation of pre-resurrection blindness: they cannot see that the one in the boat is the bread from heaven (John 6:35).</p>',
    "15": '<p>A revelation of Christ\'s warning: &ldquo;Watch out; beware of the leaven of the Pharisees and the leaven of Herod.&rdquo; Leaven in Jewish usage symbolized a pervasive corrupting influence (cf. 1 Cor 5:6–8). The Pharisees\' leaven is the sign-demanding unbelief of v.11; Herod\'s leaven is the political calculation that silenced the prophet (6:17–29). Together they represent the two temptations that will kill Jesus: religious unbelief and political convenience. Christ warns his disciples against both corruptions.</p>',
    "16": '<p>A theme of the disciples\' misunderstanding: they began discussing with one another, &ldquo;We have no bread.&rdquo; They hear the metaphorical warning and translate it into the physical provision problem they were already anxious about. The gap between what Christ says and what the disciples hear is the gap between the spiritual and the material perception — the same gap that the two-stage healing of the blind man (vv.22–26) will illustrate. Partial sight produces misread warnings.</p>',
    "17": '<p>A direct revelation of Christ\'s diagnostic insight: &ldquo;Why are you discussing the fact that you have no bread? Do you not yet perceive or understand? Are your hearts hardened?&rdquo; The hardened heart (pōrōsis kardias) is the language of Pharaonic stubbornness (Exod 4:21) applied to the disciples. The one who sees the heart (2:8) diagnoses the same condition in his followers as in his opponents — but with compassion rather than judgment. The hard heart in the disciples will be softened; the same could not be said for those who demanded signs.</p>',
    "18": '<p>A revelation of Christ citing the prophets against his own disciples: &ldquo;Having eyes do you not see, and having ears do you not hear?&rdquo; The citation echoes Jer 5:21 and Ezek 12:2 — the prophetic indictment of Israel\'s spiritual blindness. The disciples are in the same condition as the covenant people whom the prophets rebuked. The healings of blind eyes and deaf ears (7:34–35; and 8:22–26 immediately ahead) are physical enactments of the spiritual transformation Christ will produce in these same disciples through his death and resurrection.</p>',
    "19": '<p>A revelation of Christ recalling the first feeding: &ldquo;When I broke the five loaves for the five thousand, how many baskets full of broken pieces did you take up? They said to him, Twelve.&rdquo; Christ leads the disciples through the evidence they already have — not to shame them but to press toward perception. The twelve baskets (the number of Israel\'s tribes) are the measure of abundance for the Jewish community; the disciples remember the number without grasping its significance. Memory without perception is the condition Christ is correcting.</p>',
    "20": '<p>A revelation of Christ recalling the second feeding: &ldquo;And the seven for the four thousand, how many baskets full of broken pieces did you take up? And they said to him, Seven.&rdquo; The seven baskets (the number of completion and the Gentile portion) are also remembered without comprehension. The juxtaposition of twelve and seven — Israel and the nations — is the arithmetic of the universal mission that the disciples cannot yet see. They have all the evidence; they lack the eyes to read it.</p>',
    "21": '<p>A direct revelation of Christ\'s expectation: &ldquo;Do you not yet understand?&rdquo; The question is the hinge between the disciples\' blindness (vv.14–21) and the healing of the blind man (vv.22–26). Mark places the healing immediately after this question as a structural commentary: the disciples who do not yet understand are the blind men who need Christ\'s touch. The two-stage healing that follows models the two-stage understanding that Caesarea Philippi (partial) and the resurrection (complete) will bring.</p>',
    "22": '<p>A revelation of Christ as healer of spiritual blindness: they come to Bethsaida and people bring a blind man, begging Jesus to touch him. The blind man who cannot come himself and must be brought by others parallels the deaf-mute of 7:32 — both represent those who cannot approach Christ through their own faculty but are carried to him by others. The healing that follows in two stages is unique in the Gospels and functions as a type of progressive revelation.</p>',
    "23": '<p>A revelation of Christ\'s compassionate method: he takes the blind man by the hand, leads him out of the village, spits on his eyes, and lays his hands on him. The private removal from the village (cf. 7:33) protects the Messianic Secret; the saliva and touch communicate healing intention to one who cannot see the action. Christ meets each person in the language their condition allows — touch for the deaf, touch and saliva for the blind. The incarnate Lord enters each person\'s experience to bring them through it.</p>',
    "24": '<p>A revelation of partial sight as a Christological type: the man looks up and says, &ldquo;I see people, but they look like trees, walking.&rdquo; The partial sight is not a miracle failure but a deliberate two-stage healing that mirrors the disciples\' partial understanding: they have seen enough to confess that Jesus is the Messiah (v.29) but not enough to accept that the Messiah must suffer (v.32). Partial healing, like partial faith, is real but incomplete — and Christ completes what he has begun.</p>',
    "25": '<p>A direct revelation of Christ\'s complete restoration: Jesus lays his hands on the man\'s eyes again, and the man sees clearly and is restored and sees everything plainly. The complete sight that comes with the second touch is the type of the post-resurrection understanding that the disciples will receive when the Spirit opens their eyes fully (Luke 24:45; John 20:22). The pattern — incomplete sight followed by complete restoration — maps onto the entire discipleship narrative from Caesarea Philippi to Pentecost.</p>',
    "26": '<p>A theme of the Messianic Secret: Jesus sends him to his home, saying, &ldquo;Do not even enter the village.&rdquo; The healed blind man is the last person sent away with a secrecy command before the public Petrine confession at Caesarea Philippi. The Messianic Secret reaches its climax: Jesus has given every physical sign of the messianic age while suppressing the public identification. The reason is now about to be revealed — he is the Messiah of the cross, not of popular expectation.</p>',
    "27": '<p>A revelation of the Christological center of Mark: Jesus goes to the villages of Caesarea Philippi and asks his disciples, &ldquo;Who do people say that I am?&rdquo; Caesarea Philippi is both geographically and theologically the midpoint — geographically at the foot of Hermon, theologically at the confession that defines Mark\'s Christology. The question is the one the whole first half of the Gospel has been building toward: in the light of the exorcisms, healings, feedings, and teaching, who is this?</p>',
    "28": '<p>A revelation of inadequate perceptions: John the Baptist, Elijah, one of the prophets — the popular identifications are all within the prophetic category but fall short of the divine sonship that the Gospel\'s opening declared. The crowd sees a prophet; the Gospel has shown the Son of God. The gap between public perception and revealed identity is the gap that the disciples must cross, and that the church must cross in every generation: Jesus is not the highest example of a known category but a new and unprecedented category of being.</p>',
    "29": '<p>A direct revelation: Peter answered him, You are the Christ. The Petrine confession at Caesarea Philippi is the structural center of Mark\'s Gospel. The immediate sequence that follows is theologically decisive: the Messianic Secret (silence commanded), the passion prediction (the Christ will suffer and die), and the call to cross-bearing. Mark\'s Christological argument is that the Messiah is only correctly understood as the Suffering Servant — to confess the Christ without the cross is to confess a misunderstood Christ. Peter\'s rebuke (v.32) and Jesus\'s sharp response (get behind me, Satan) demonstrate that Messiahship divorced from suffering is a Satanic distortion, not a divine truth.</p>',
    "30": '<p>A theme of the Messianic Secret at its turning point: he charged them to tell no one about him. After the confession, the secrecy command applies to the disciples themselves — they are not to announce what they have confessed until the passion and resurrection give the confession its correct content. To declare &ldquo;Jesus is the Christ&rdquo; without the cross produces the misunderstanding Peter demonstrates in v.32. The silence protects the confession from being received on wrong terms.</p>',
    "31": '<p>A direct revelation: he began to teach them that the Son of Man must suffer many things and be rejected by the elders and the chief priests and the scribes and be killed and after three days rise again. The first passion prediction is the theological core of Mark\'s Gospel. The &ldquo;must&rdquo; (dei) is the divine necessity of the scriptural plan — the Son of Man\'s suffering is not an accident but the fulfillment of what the prophets wrote (Isa 53; Ps 118:22). The Danielic Son of Man (7:13) is also the Isaianic Servant (53:3–12); the one who receives the kingdom is the one who gives his life. The three-day resurrection is announced alongside the death — they are inseparable.</p>',
    "32": '<p>A revelation of Christ and Peter: he said this plainly, and Peter took him aside and began to rebuke him. The plainness (parrēsia) of the passion prediction means it was unmistakable; Peter\'s rebuke shows that the disciples wanted the Christ of glory without the Christ of the cross. The rebuke of a teacher by a student was a serious breach of honor — Peter is not merely expressing concern but asserting that Jesus has misunderstood his own destiny. The response shows how gravely Christ views this Christological error.</p>',
    "33": '<p>A direct revelation: turning and seeing his disciples, he rebuked Peter and said, &ldquo;Get behind me, Satan! For you are not setting your mind on the things of God, but on the things of men.&rdquo; The sharpest rebuke in Mark is given to the disciple who just confessed correctly. The cross-free Messianism that Peter advocates is identified as Satanic — not because Peter is possessed, but because the temptation to avoid the cross was the devil\'s original strategy (Matt 4:8–9). Human ideas of what the Messiah should be are the things of men; the cross is the thing of God.</p>',
    "34": '<p>A direct revelation: if anyone wishes to come after me, let him deny himself and take up his cross and follow me. The cross is not a Markan metaphor for general difficulty but a specific path: the path Christ himself walked. Discipleship in Mark is defined by cross-bearing — sharing the master\'s path of self-denial, rejection, suffering, and death in the confidence of resurrection. The cross-bearing community is the community shaped by the Christology: the Son of God who died reveals what it means to follow the Son of God who died. Mark\'s suffering community (addressed in the Roman persecution context) is being told that their cross-bearing is not a contradiction of the gospel but its confirmation.</p>',
    "35": '<p>A direct revelation of the gospel\'s paradox: &ldquo;Whoever would save his life will lose it, but whoever loses his life for my sake and the gospel\'s will save it.&rdquo; The double reference — &ldquo;for my sake and the gospel\'s&rdquo; — places Christ and the gospel in apposition: to lose one\'s life for the gospel is to lose it for Christ, because Christ is the gospel. The paradox is not a spiritual technique but a description of the way Christ\'s death-and-resurrection pattern works: the life laid down in faith is the life received back in resurrection.</p>',
    "36": '<p>A revelation of Christ\'s eternal-value framework: &ldquo;For what does it profit a man to gain the whole world and forfeit his soul?&rdquo; The question reframes every calculation of gain and loss in terms of the soul\'s eternal worth. Christ has come to give his life as a ransom for many (10:45) because he knows the soul\'s value exceeds every earthly accumulation. The one who knows the exchange rate — because he is the ransom price — speaks with absolute authority about what is worth having.</p>',
    "37": '<p>A revelation of Christ as the source of redemption: &ldquo;For what can a man give in return for his soul?&rdquo; The rhetorical question has no answer in human terms — there is nothing a person possesses that is equal to the soul\'s worth or adequate to purchase its redemption. But Christ has the answer in his own person: the ransom is his life (10:45), the price that only the Son of God can pay. The question that no human can answer, the gospel answers in the cross.</p>',
    "38": '<p>A direct revelation: &ldquo;Whoever is ashamed of me and of my words in this adulterous and sinful generation, of him will the Son of Man also be ashamed when he comes in the glory of his Father with the holy angels.&rdquo; The final Christological claim of chapter 8: the humiliated Son of Man who will be rejected by elders, priests, and scribes (v.31) is the same Son of Man who will come in glory as the divine Judge. Shame in the face of the cross leads to shame at the face of the throne. The eschatological Son of Man standing before the Father\'s glory is the same one asking for loyalty in Galilee.'
  }
}

def main():
    existing = load_comm('mkt-christ', 'mark')
    merge_comm(existing, MARK_CH7_8)
    save_comm('mkt-christ', 'mark', existing)
    ch7 = len(existing.get('7', {}))
    ch8 = len(existing.get('8', {}))
    print(f'Mark 7: {ch7} verses, Mark 8: {ch8} verses.')

if __name__ == '__main__':
    main()
